  'Teams_Premium_(for_Departments)': 'Teams Premium (for Departments)',
  'WACONEDRIVEENTERPRISE': 'OneDrive for Business (Plan 2)'
};

function genericTitleCase(skuPartNumber) {
  return skuPartNumber.replace(/_/g, ' ').split(' ').map(word => {
    if (!word) return word;
    const isAcronym = word.length <= 4 && word === word.toUpperCase() && /^[A-Z0-9]+$/.test(word);
    if (isAcronym) return word;
    return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
  }).join(' ');
}

function friendlyName(skuPartNumber) {
  if (SKU_FRIENDLY_NAMES[skuPartNumber]) return SKU_FRIENDLY_NAMES[skuPartNumber];
  return genericTitleCase(skuPartNumber);
}

const selectedRaw = $('New Hire Form').item.json['License Type'];
const selectedList = Array.isArray(selectedRaw) ? selectedRaw : (selectedRaw ? [selectedRaw] : []);
const targetFriendlyNames = selectedList.map(s => s.split(' (')[0].trim());

const tenantFirst = $('Check License (Reenable Path)').item.json;
const skus = Array.isArray(tenantFirst?.value) ? tenantFirst.value : (Array.isArray(tenantFirst) ? tenantFirst : []);

const currentFirst = $input.all()[0]?.json;
const currentDetails = Array.isArray(currentFirst?.value) ? currentFirst.value : (Array.isArray(currentFirst) ? currentFirst : []);

const licenses = targetFriendlyNames.map(targetFriendlyName => {
  const sku = skus.find(s => friendlyName(s.skuPartNumber) === targetFriendlyName);
  if (!sku) {
    return { licenseName: targetFriendlyName, licenseAvailable: false, availableUnits: 0, skuId: null, skuPartNumber: null, alreadyAssigned: false };
  }
  const total = sku.prepaidUnits?.enabled ?? 0;
  const consumed = sku.consumedUnits ?? 0;
  const available = total - consumed;
  const alreadyAssigned = currentDetails.some(d => d.skuPartNumber === sku.skuPartNumber);
  return { licenseName: friendlyName(sku.skuPartNumber), licenseAvailable: available > 0, availableUnits: available, skuId: sku.skuId, skuPartNumber: sku.skuPartNumber, alreadyAssigned };
});

const availableLicenses = licenses.filter(l => l.licenseAvailable);
const unavailableLicenses = licenses.filter(l => !l.licenseAvailable);

const requestedSkuPartNumbers = licenses.map(l => l.skuPartNumber).filter(Boolean);
const licensesToAdd = availableLicenses.filter(l => !l.alreadyAssigned);
const licensesToRemove = currentDetails
  .filter(d => !requestedSkuPartNumbers.includes(d.skuPartNumber))
  .map(d => ({ skuId: d.skuId, licenseName: friendlyName(d.skuPartNumber) }));

return [{ json: { licenses, availableLicenses, unavailableLicenses, licensesToAdd, licensesToRemove, anyAvailable: availableLicenses.length > 0, allAvailable: unavailableLicenses.length === 0, anyChange: licensesToAdd.length > 0 || licensesToRemove.length > 0 } }];

